@namespace Lumeo
@implements IAsyncDisposable
@inject Lumeo.Services.IComponentInteropService Interop

@{
    var context = new TooltipContext(_isOpen, _wrapperId, _contentId);
}

@* aria-describedby links the trigger region to the role=tooltip content so
   screen readers announce it — the tooltip's whole a11y purpose. @onfocusin /
   @onfocusout bubble from the focusable child (e.g. a Button), giving keyboard
   parity with hover; Escape dismisses per the WAI-ARIA tooltip pattern. *@
<div id="@_wrapperId" class="@Cx.Merge("relative inline-flex", Class)"
     aria-describedby="@(_isOpen ? _contentId : null)"
     @onmouseenter="HandleMouseEnter"
     @onmouseleave="HandleMouseLeave"
     @onfocusin="HandleFocusIn"
     @onfocusout="HandleFocusOut"
     @onkeydown="HandleKeyDown"
     @onclick="HandleTap"
     @attributes="AdditionalAttributes">
    <CascadingValue Value="context" IsFixed="false">
        @ChildContent
    </CascadingValue>
</div>

@code {
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public int ShowDelay { get; set; } = 200;
    [Parameter] public int HideDelay { get; set; } = 0;

    /// <summary>
    /// Extra classes for the tooltip's wrapper element (the <c>relative inline-flex</c>
    /// box around the trigger). Merged via <see cref="Cx.Merge"/> so a consumer class
    /// wins conflicts without <c>!important</c> — e.g. <c>Class="w-full"</c> makes the
    /// wrapper fill its parent so a full-width trigger (e.g. a sidebar nav button) is
    /// not shrunk to content width.
    /// </summary>
    [Parameter] public string? Class { get; set; }

    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private readonly string _wrapperId = LumeoIds.New("tooltip-wrapper");
    // Stable content id shared with TooltipContent so the trigger's
    // aria-describedby can reference it.
    private readonly string _contentId = LumeoIds.New("tooltip-content");
    private bool _hovered;
    private bool _focused;
    // rc.44 — on touch devices a tap "pins" the tooltip open until the next
    // tap elsewhere (registerClickOutside also now listens for touchstart, so
    // dismissal works equally on mobile).
    private bool _pinned;
    private bool _clickOutsideRegistered;
    private readonly DelayedDispatch _dispatch = new();

    private bool _isOpen => _hovered || _pinned || _focused;

    private void HandleMouseEnter()
    {
        _dispatch.Cancel();
        if (ShowDelay <= 0)
        {
            _hovered = true;
            StateHasChanged();
        }
        else
        {
            _dispatch.Schedule(ShowDelay, () => InvokeAsync(() =>
            {
                _hovered = true;
                StateHasChanged();
                return Task.CompletedTask;
            }));
        }
    }

    private void HandleMouseLeave()
    {
        _dispatch.Cancel();
        if (HideDelay <= 0)
        {
            _hovered = false;
            StateHasChanged();
        }
        else
        {
            _dispatch.Schedule(HideDelay, () => InvokeAsync(() =>
            {
                _hovered = false;
                StateHasChanged();
                return Task.CompletedTask;
            }));
        }
    }

    // Keyboard parity: focusing the trigger (or any focusable child) shows the
    // tooltip immediately; blur hides it. Radix opens HoverCard/Tooltip on
    // keyboard focus so keyboard-only users can read it.
    private void HandleFocusIn()
    {
        _dispatch.Cancel();
        _focused = true;
        StateHasChanged();
    }

    private void HandleFocusOut()
    {
        _focused = false;
        StateHasChanged();
    }

    // Escape dismisses the tooltip (clears hover + focus state) per WAI-ARIA.
    private void HandleKeyDown(KeyboardEventArgs e)
    {
        if (e.Key == "Escape")
        {
            // Clear the pinned (tap-to-stick) state too, otherwise Escape leaves a
            // pinned tooltip open.
            _dispatch.Cancel();
            _pinned = false;
            _hovered = false;
            _focused = false;
            StateHasChanged();
        }
    }

    // Tap toggles the pinned state. The first tap on a touch device fires
    // both `mouseenter` (browser-emulated) and `click` — that's fine: pin
    // simply sticks open. A second tap on the trigger unpins.
    private async Task HandleTap()
    {
        _pinned = !_pinned;
        if (_pinned && !_clickOutsideRegistered)
        {
            await Interop.RegisterClickOutside(_wrapperId, null, OnClickOutside);
            _clickOutsideRegistered = true;
        }
        StateHasChanged();
    }

    private Task OnClickOutside()
    {
        if (_pinned)
        {
            _pinned = false;
            _hovered = false;
            StateHasChanged();
        }
        return Task.CompletedTask;
    }

    public async ValueTask DisposeAsync()
    {
        _dispatch.Dispose();
        if (_clickOutsideRegistered)
        {
            try { await Interop.UnregisterClickOutside(_wrapperId); }
            catch (Microsoft.JSInterop.JSDisconnectedException) { }
            _clickOutsideRegistered = false;
        }
    }

    public record TooltipContext(bool IsOpen, string WrapperId, string ContentId);
}

@namespace Lumeo
@implements IAsyncDisposable

@*  rc.45 — fixed-position rendering + collision flip.
    Previously the tooltip was an absolutely positioned child of the trigger
    wrapper, anchored with Tailwind classes (`bottom-full start-1/2 ...`).
    That meant a tooltip near the viewport edge clipped against it.
    We now mirror the Popover pattern: render with `position: fixed`, hand
    placement off to `ComponentInteropService.PositionFixed` (floating-ui
    under the hood), which auto-flips to the opposite side when collision
    space is tight. Side is still consumer-controlled as a preference. *@
@if (IsOpen)
{
    <div id="@_contentId" role="tooltip" class="@CssClass" @attributes="AdditionalAttributes">
        @ChildContent
        @if (ShowArrow)
        {
            <div class="@ArrowClasses"></div>
        }
    </div>
}

@inject Lumeo.Services.IComponentInteropService Interop

@code {
    [CascadingParameter] public Tooltip.TooltipContext? Context { get; set; }

    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public Lumeo.Side Side { get; set; } = Lumeo.Side.Top;
    [Parameter] public bool ShowArrow { get; set; } = true;
    [Parameter] public int Offset { get; set; } = 8;
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    // Use the content id from the Tooltip parent so the trigger's
    // aria-describedby points at this role=tooltip element.
    private string _contentId => Context?.ContentId ?? string.Empty;
    private bool _registered;

    private bool IsOpen => Context?.IsOpen ?? false;

    private string CssClass => Cx.Merge(
        "fixed z-50 overflow-visible rounded-md bg-primary px-3 py-1.5 text-xs text-primary-foreground",
        AnimationClasses,
        Class);

    private string AnimationClasses => IsOpen
        ? "opacity-100 visible animate-fade-in"
        : "opacity-0 invisible";

    private string SideStr => Side switch
    {
        Lumeo.Side.Top => "top",
        Lumeo.Side.Bottom => "bottom",
        Lumeo.Side.Left => "left",
        Lumeo.Side.Right => "right",
        _ => "top"
    };

    // Rotated square — same visual as Popover/HoverCard but no border (tooltip is a solid primary surface).
    private string ArrowClasses => Side switch
    {
        Lumeo.Side.Top => "absolute start-1/2 top-full -translate-x-1/2 -translate-y-1/2 rotate-45 h-2 w-2 bg-primary",
        Lumeo.Side.Bottom => "absolute start-1/2 bottom-full -translate-x-1/2 translate-y-1/2 rotate-45 h-2 w-2 bg-primary",
        Lumeo.Side.Left => "absolute top-1/2 left-full -translate-y-1/2 -translate-x-1/2 rotate-45 h-2 w-2 bg-primary",
        Lumeo.Side.Right => "absolute top-1/2 right-full -translate-y-1/2 translate-x-1/2 rotate-45 h-2 w-2 bg-primary",
        _ => "absolute start-1/2 top-full -translate-x-1/2 -translate-y-1/2 rotate-45 h-2 w-2 bg-primary"
    };

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (IsOpen && !_registered && Context is not null)
        {
            await Interop.PositionFixed(_contentId, Context.WrapperId, "center", false, SideStr, Offset);
            _registered = true;
        }
        else if (!IsOpen && _registered)
        {
            await Cleanup();
        }
    }

    private async Task Cleanup()
    {
        try { await Interop.UnpositionFixed(_contentId); }
        catch (Microsoft.JSInterop.JSDisconnectedException) { }
        _registered = false;
    }

    public async ValueTask DisposeAsync()
    {
        if (_registered) await Cleanup();
    }

}

@namespace Lumeo

@if (AsChild)
{
    @* asChild: render NO wrapper. Cascade the slot so a cooperating child (a Lumeo
       <Button>, or a manual <ChildContentSlot> splat) becomes the single trigger
       element. Tooltip's open/close behaviour lives on the Tooltip ROOT wrapper and
       is driven by bubbled mouseenter/focusin, so the slot carries NO handlers — its
       sole job is to put aria-describedby on the actual focusable element. An ancestor
       <div> can't describe the inner button, so without asChild a screen reader never
       announces the tooltip on focus; folding it onto the child fixes that. *@
    <CascadingValue Value="Slot" IsFixed="false">
        @if (ChildContentSlot is not null)
        {
            @ChildContentSlot(Slot)
        }
        else
        {
            @ChildContent
        }
    </CascadingValue>
}
else
{
    <div class="@CssClass" @attributes="AdditionalAttributes">
        @ChildContent
    </div>
}

@code {
    [CascadingParameter] public Tooltip.TooltipContext Context { get; set; } = default!;
    [Parameter] public RenderFragment? ChildContent { get; set; }

    /// <summary>
    /// Tier-2 escape hatch for <see cref="AsChild"/> with arbitrary (non-Lumeo) markup:
    /// receives the <see cref="TriggerSlot"/> so the consumer can splat
    /// <c>@attributes="slot.Attributes"</c> onto their own single element (which adds
    /// the <c>aria-describedby</c> when the tooltip is open). Lumeo <c>&lt;Button&gt;</c>
    /// children need only <see cref="AsChild"/> — they consume the slot automatically.
    /// </summary>
    [Parameter] public RenderFragment<TriggerSlot>? ChildContentSlot { get; set; }

    /// <summary>
    /// When <c>true</c>, the trigger renders NO wrapper element and instead cascades a
    /// <see cref="TriggerSlot"/> that a cooperating child folds onto its own single root
    /// element. The key effect is correct a11y: <c>aria-describedby</c> lands on the
    /// real focusable control (so a screen reader announces the tooltip on focus) rather
    /// than on a non-focusable wrapper <c>&lt;div&gt;</c>. Hover/focus open-close still
    /// works via the events bubbling to the Tooltip root. Default <c>false</c> preserves
    /// the current <c>inline-flex</c> wrapper exactly.
    /// </summary>
    [Parameter] public bool AsChild { get; set; }

    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private string CssClass => Cx.Merge("inline-flex", Class);

    private TriggerSlot Slot => new(
        Id: null,                                 // Tooltip anchors positioning on its root wrapper, not the trigger
        Class: Cx.Merge("inline-flex", Class),
        Attributes: BuildAttrs(),
        OnClick: default);                        // behaviour bubbles to the Tooltip root; no handler on the child

    private IReadOnlyDictionary<string, object> BuildAttrs()
    {
        var d = new Dictionary<string, object>();
        // aria-describedby must reference the role=tooltip content from the FOCUSABLE
        // element so the screen reader announces it on focus (only while open — the
        // content isn't in the DOM when closed).
        if (Context.IsOpen) d["aria-describedby"] = Context.ContentId;
        if (AdditionalAttributes is not null)
            foreach (var kv in AdditionalAttributes) d[kv.Key] = kv.Value; // author wins on collision
        return d;
    }
}
